vector<int> build_fail(const string& p) {
  int n = p.size();
  vector<int> fail(n, 0);
  for (int i = 1; i < n; ++i) {
    int j = fail[i - 1];
    while (p[i] != p[j]) {  // 缺少 j > 0 判断
      j = fail[j - 1];      // j=0 时 fail[-1] 越界
    }
    if (p[i] == p[j]) j++;
    fail[i] = j;
  }
  return fail;
}
```

错误点：当 j 已经为 0 仍不匹配时，应停止回跳，而不是继续访问 fail[-1]。

mistakes.correct_answer_markdown:
```cpp
vector<int> build_fail(const string& p) {
  int n = p.size();
  vector<int> fail(n, 0);
  for (int i = 1; i < n; ++i) {
    int j = fail[i - 1];
    while (j > 0 && p[i] != p[j]) {  // 多了 j > 0
      j = fail[j - 1];
    }
    if (p[i] == p[j]) j++;
    fail[i] = j;
  }
  return fail;
}
```

