int qpow(int a, int b, int p) {
  int res = 1, base = a % p;
  while (b) {
    if (b & 1) res = res * base % p;  // res * base 在 int 中溢出
    base = base * base % p;            // 同样溢出
    b >>= 1;
  }
  return res;
}
